SciNum={}SciNum.__index=SciNum;local a=20;local b=50;local function c(d)if#d==0 or d=="0"then return"0.0",0 end;if d=="0.0"or d=="0e0"or d=="0E0"then return"0.0",0 end;local e=""local f=1;local g=d:sub(1,1)if g=="-"then e="-"f=2 elseif g=="+"then f=2 end;local h=d:sub(f,f+b)local i=h:find("[eE]")if i then local j=h:sub(1,i-1)local k=h:sub(i+1)local l=tonumber(k)or 0;return e..j,l end;local m=d:sub(f,f+b)local n=m:find("%.")local o=15;if not n then local p=#d-f+1;if p>o then local q=d:sub(f,f+o-1)return e..q:sub(1,1).."."..q:sub(2),p-1 else if p==1 then return e..d:sub(f,f)..".0",0 else return e..d:sub(f,f).."."..d:sub(f+1),p-1 end end else local r=m:sub(1,n-1)local s=m:sub(n+1)local t=r..s;t=t:gsub("^0+","")if#t==0 then return"0.0",0 end;local u=#r-1;if r=="0"then local v=s:find("[1-9]")if not v then return"0.0",0 end;u=-v;t=s:sub(v)end;if#t>o then t=t:sub(1,o)end;return e..t:sub(1,1).."."..t:sub(2),u end end;function SciNum.new(d)local w,u=c(d)w=tonumber(w)u=tonumber(u)local self=setmetatable({},SciNum)while w>=10 do w=w/10;u=u+1 end;while w<1 and w>0 do w=w*10;u=u-1 end;self.base=tonumber(string.format("%.10f",w))self.exponent=u;return self end;function SciNum:tostring()if math.abs(self.exponent)<=12 then local x=self.base*10^self.exponent;return x else local y=string.format("%.10f",self.base)y=y:match("^(.-)0*$")y=y:gsub("%.$","")local z=string.format("%se%d",y,self.exponent)return z end end;function SciNum:tostringServer()if math.abs(self.exponent)<=12 then local x=self.base*10^self.exponent;return tostring(x)else local y=string.format("%.10f",self.base)y=y:match("^(.-)0*$")y=y:gsub("%.$","")local z=string.format("%se+%d",y,self.exponent)return z end end;local function A(B)if getmetatable(B)==SciNum then return B elseif type(B)=="string"or type(B)=="number"then return SciNum.new(B)else LogTool.Error('SciNum',"Cannot convert value of type "..type(B).." to SciNum object")end end;function SciNum:add(B)B=A(B)if math.abs(self.exponent-B.exponent)>a then if self.exponent>B.exponent then return self else return B end end;if self.exponent>B.exponent then self.base=self.base*10^(self.exponent-B.exponent)self.exponent=B.exponent elseif self.exponent<B.exponent then B.base=B.base*10^(B.exponent-self.exponent)B.exponent=self.exponent end;local y=self.base+B.base;local C=self.exponent;while y>=10 do y=y/10;C=C+1 end;y=tonumber(string.format("%.10f",y))return SciNum.new(string.format("%.10fe%d",y,C))end;function SciNum:subtract(B)B=A(B)if math.abs(self.exponent-B.exponent)>a then if self.exponent>B.exponent then return self else local D=SciNum.new("-"..B:tostring())return D end end;if self.exponent>B.exponent then self.base=self.base*10^(self.exponent-B.exponent)self.exponent=B.exponent elseif self.exponent<B.exponent then B.base=B.base*10^(B.exponent-self.exponent)B.exponent=self.exponent end;local y=self.base-B.base;local C=self.exponent;while y<1 and y>0 do y=y*10;C=C-1 end;y=tonumber(string.format("%.10f",y))return SciNum.new(string.format("%.10fe%d",y,C))end;function SciNum:multiply(B)B=A(B)local y=self.base*B.base;local C=self.exponent+B.exponent;local E=y<0;y=math.abs(y)if y==0 then C=0 else while y<1 and y>0 do y=y*10;C=C-1 end end;y=E and-y or y;y=tonumber(string.format("%.10f",y))return SciNum.new(string.format("%.10fe%d",y,C))end;function SciNum:divide(B)B=A(B)if B.base==0 and B.exponent==0 then return SciNum.new("0")end;local y=self.base/B.base;local C=self.exponent-B.exponent;local E=y<0;y=math.abs(y)if y==0 then C=0 else while y<1 and y>0 do y=y*10;C=C-1 end end;y=E and-y or y;y=tonumber(string.format("%.10f",y))return SciNum.new(string.format("%.10fe%d",y,C))end;function SciNum:compare(B)B=A(B)if self.exponent>B.exponent then return 1 elseif self.exponent<B.exponent then return-1 else if self.base>B.base then return 1 elseif self.base<B.base then return-1 else return 0 end end end;function SciNum:toPercentage()local F=308;local G=-308;local H=math.max(G,math.min(self.exponent,F))local d=self.base*10^H;local I=d*100;if I<0.1 then return 0.1,"0.1%"elseif I>999 then return 999,"999%"else local J=tonumber(string.format("%.2f",I))return J,string.format("%.2f%%",J)end end;return SciNum